function renderAttendanceHistory() {
    const history = getAttendanceHistory();
    const container = document.getElementById('attendance-history-list');
    if (!container) return;

    if (history.length === 0) {
        container.innerHTML = '<p style="text-align:center; padding: 30px; color: var(--text-muted);">ไม่มีประวัติบันทึกการเช็คชื่อเข้าเรียน</p>';
        return;
    }

    const classFilter = document.getElementById('history-class-filter') ? document.getElementById('history-class-filter').value : 'all';
    const roomFilter = document.getElementById('history-room-filter') ? document.getElementById('history-room-filter').value : 'all';

    // Filter history first while keeping original index
    const filteredHistory = [];
    history.forEach((h, originalIndex) => {
        const matchClass = (classFilter === 'all' || (h.class || 'm3') === classFilter);
        const matchRoom = (roomFilter === 'all' || (h.room || '1') === roomFilter);
        if (matchClass && matchRoom) {
            filteredHistory.push({ ...h, originalIndex });
        }
    });

    if (filteredHistory.length === 0) {
        container.innerHTML = '<p style="text-align:center; padding: 30px; color: var(--text-muted);">ไม่พบข้อมูลประวัติการเข้าเรียนตามตัวกรองที่เลือก</p>';
        return;
    }

    // Helper to parse Thai date
    function parseThaiDate(dateStr) {
        const parts = dateStr.split(' ');
        if (parts.length < 3) return { day: 1, month: 'มิ.ย.', year: 2569, monthIndex: 5, monthFull: 'มิถุนายน' };
        const day = parseInt(parts[0]);
        const month = parts[1];
        const year = parseInt(parts[2]);
        const shortMonths = ['ม.ค.', 'ก.พ.', 'มี.ค.', 'เม.ย.', 'พ.ค.', 'มิ.ย.', 'ก.ค.', 'ส.ค.', 'ก.ย.', 'ต.ค.', 'พ.ย.', 'ธ.ค.'];
        const fullMonths = ['มกราคม', 'กุมภาพันธ์', 'มีนาคม', 'เมษายน', 'พฤษภาคม', 'มิถุนายน', 'กรกฎาคม', 'สิงหาคม', 'กันยายน', 'ตุลาคม', 'พฤศจิกายน', 'ธันวาคม'];
        const monthIndex = shortMonths.indexOf(month);
        return {
            day: day,
            month: month,
            year: year,
            monthIndex: monthIndex !== -1 ? monthIndex : 0,
            monthFull: monthIndex !== -1 ? fullMonths[monthIndex] : month
        };
    }

    // Group by Month & Year
    const grouped = {};
    filteredHistory.forEach((h) => {
        const dateInfo = parseThaiDate(h.date);
        const key = `${dateInfo.monthFull} ${dateInfo.year}`;
        if (!grouped[key]) {
            grouped[key] = {
                key: key,
                monthFull: dateInfo.monthFull,
                year: dateInfo.year,
                monthIndex: dateInfo.monthIndex,
                records: [],
                totalDays: 0,
                presentSum: 0,
                lateSum: 0,
                leaveSum: 0,
                absentSum: 0,
                rateSum: 0
            };
        }
        grouped[key].records.push({ ...h, dateInfo: dateInfo });

        grouped[key].totalDays += 1;
        grouped[key].presentSum += h.present || 0;
        grouped[key].lateSum += h.late || 0;
        grouped[key].leaveSum += h.leave || 0;
        grouped[key].absentSum += h.absent || 0;
        grouped[key].rateSum += h.rate || 0;
    });

    // Sort reverse chronologically
    const groupsArray = Object.values(grouped).sort((a, b) => {
        if (a.year !== b.year) return b.year - a.year;
        return b.monthIndex - a.monthIndex;
    });

    // Build Monthly Cards Grid HTML
    let overviewHTML = '<div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 16px; margin-bottom: 25px;">';

    groupsArray.forEach(group => {
        const avgRate = Math.round(group.rateSum / group.totalDays);
        const monthlyRateColor = avgRate >= 90 ? 'var(--success)' : avgRate >= 70 ? 'var(--warning)' : 'var(--danger)';
        overviewHTML += `
            <div class="attendance-month-card" style="background: var(--white); border: 1px solid var(--border); border-radius: 16px; padding: 18px; box-shadow: var(--shadow-sm); border-left: 4px solid var(--primary); display: flex; flex-direction: column; gap: 12px; transition: all 0.2s ease; cursor: pointer;" onclick="toggleMonthAccordion('${group.key}')">
                <div style="display: flex; justify-content: space-between; align-items: flex-start;">
                    <div>
                        <h4 style="margin: 0; font-size: 1.1rem; font-weight: 700; color: var(--text-main);"><i class="fa-solid fa-calendar-check" style="color: var(--primary); margin-right: 6px;"></i> ${group.key}</h4>
                        <p style="margin: 2px 0 0 0; font-size: 0.82rem; color: var(--text-muted); font-weight: 500;">บันทึกทั้งหมด: ${group.totalDays} วัน</p>
                    </div>
                    <div style="text-align: right;">
                        <span style="font-size: 1.3rem; font-weight: 800; color: ${monthlyRateColor};">${avgRate}%</span>
                        <p style="margin: 0; font-size: 0.72rem; color: var(--text-muted); font-weight: 600;">เข้าเรียนเฉลี่ย</p>
                    </div>
                </div>
                <div style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 6px; background: var(--secondary); padding: 8px; border-radius: 10px; text-align: center;">
                    <div>
                        <span style="font-size: 0.85rem; font-weight: 700; color: var(--success);">${group.presentSum}</span>
                        <span style="display: block; font-size: 0.65rem; color: var(--text-muted); font-weight: 500;">มาเรียน</span>
                    </div>
                    <div>
                        <span style="font-size: 0.85rem; font-weight: 700; color: var(--warning);">${group.lateSum}</span>
                        <span style="display: block; font-size: 0.65rem; color: var(--text-muted); font-weight: 500;">สาย</span>
                    </div>
                    <div>
                        <span style="font-size: 0.85rem; font-weight: 700; color: #7c3aed;">${group.leaveSum}</span>
                        <span style="display: block; font-size: 0.65rem; color: var(--text-muted); font-weight: 500;">ลา</span>
                    </div>
                    <div>
                        <span style="font-size: 0.85rem; font-weight: 700; color: var(--danger);">${group.absentSum}</span>
                        <span style="display: block; font-size: 0.65rem; color: var(--text-muted); font-weight: 500;">ขาด</span>
                    </div>
                </div>
            </div>
        `;
    });
    overviewHTML += '</div>';

    // Build Collapsible Accordions HTML
    let listHTML = `
        <h3 style="font-size: 1.05rem; font-weight: 600; color: var(--text-main); margin: 25px 0 15px 0; display: flex; align-items: center; gap: 8px;">
            <i class="fa-solid fa-list-check" style="color: var(--primary);"></i> รายละเอียดการเช็คชื่อรายวันแยกตามเดือน
        </h3>
    `;

