        const avgRate = Math.round(group.rateSum / group.totalDays);
        const monthlyRateColor = avgRate >= 90 ? 'var(--success)' : avgRate >= 70 ? 'var(--warning)' : 'var(--danger)';
        const isDefaultOpen = groupIndex === 0;
        const displayStyle = isDefaultOpen ? 'block' : 'none';
        const arrowTransform = isDefaultOpen ? 'rotate(0deg)' : 'rotate(-90deg)';

        let dailyRowsHTML = '';
