            const rateColor = h.rate >= 90 ? 'var(--success)' : h.rate >= 70 ? 'var(--warning)' : 'var(--danger)';
            const classLabel = h.class === 'm1' ? 'ม.1' : h.class === 'm2' ? 'ม.2' : h.class === 'm3' ? 'ม.3' : 'ม.3';
            const roomLabel = h.room ? `/${h.room}` : '/1';
            dailyRowsHTML += `
                <div class="attendance-daily-row" style="display: flex; justify-content: space-between; align-items: center; padding: 14px 16px; border-bottom: 1px solid var(--border); transition: background 0.2s;">
                    <div style="display: flex; flex-direction: column; gap: 4px;">
                        <div style="display: flex; align-items: center; gap: 8px;">
                            <span style="font-size: 0.95rem; font-weight: 600; color: var(--text-main);">${h.date}</span>
                            <span style="font-size: 0.8rem; background: var(--primary-light); color: var(--primary-dark); padding: 2px 8px; border-radius: 6px; font-weight: 500;">ห้อง ${classLabel}${roomLabel}</span>
