                            <span>ลา: <strong style="color: #7c3aed;">${h.leave || 0}</strong></span>
                            <span style="color: var(--border); opacity: 0.5;">|</span>
                            <span>ขาด: <strong style="color: var(--danger);">${h.absent}</strong></span>
                        </div>
                    </div>
                    <div style="display: flex; align-items: center; gap: 20px;">
